//! gemma4-paris-probe — DETERMINISTIC local CPU ground-truth probe.
//!
//! Feeds the gemma4 forward KNOWN-CORRECT input token IDs (bypassing the
//! flaky live HuggingFace tokenizer and the slow Cloud Run mesh) and reads
//! the argmax of the next-token logits. This isolates the model math from
//! the tokenizer: if the argmax is "Paris" on correct input, the model is
//! fixed and any live failure is purely the tokenizer.
//!
//! Mirrors `gemma4-pipeline-smoke.rs` exactly (the proven dense forward
//! path: manual sqrt(hidden)-scaled embed, chunked attn/gate/up/down over
//! all layers, lm_head_only with the tanh softcap) but adds a CLI contract:
//!   --knot <path>        dense .knot file
//!   --tokens a,b,c       comma-separated input token IDs
//!   --expected <id>      argmax token id we expect (exit 0 on match)
//!
//! Set GEMMA4_DBG=2 to dump per-layer last-token residual values ([g4val])
//! for bisecting a model bug.
//!
//! Usage:
//!   cargo run --release --bin gemma4-paris-probe -- \
//!     --knot /tmp/gemma4-12b-it.knot \
//!     --tokens 2,105,2364,107,669,5279,529,7001,563,106,107,105,4368,107 \
//!     --expected 9079

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::math::{
    dequantize_q4k_row, dequantize_q5_0_row, dequantize_q5k_row, dequantize_q6k_row,
    dequantize_q8_0_row,
};
use distributed_inference::model::{bytes_to_f32_slice, dequantize_f16_row, QType};
// dequantize_f16_row lives in `model` (re-checked: model.rs:565), the q*_row
// dequantizers in `math`. bytes_to_f32_slice + QType in `model`.
use distributed_inference::model_gemma4::Gemma4Pipeline;

fn die(msg: impl AsRef<str>) -> ! {
    eprintln!("gemma4-paris-probe: {}", msg.as_ref());
    std::process::exit(2);
}

struct Args {
    knot: String,
    tokens: Vec<u32>,
    expected: Option<u32>,
    top_k: usize,
}

fn parse_args() -> Args {
    let raw: Vec<String> = env::args().skip(1).collect();
    let mut knot: Option<String> = None;
    let mut tokens_str: Option<String> = None;
    let mut expected: Option<u32> = None;
    let mut top_k: usize = 5;

    let mut i = 0usize;
    while i < raw.len() {
        match raw[i].as_str() {
            "--knot" => {
                i += 1;
                knot = Some(raw.get(i).unwrap_or_else(|| die("--knot needs a path")).clone());
            }
            "--tokens" => {
                i += 1;
                tokens_str = Some(
                    raw.get(i)
                        .unwrap_or_else(|| die("--tokens needs a comma-separated list"))
                        .clone(),
                );
            }
            "--expected" => {
                i += 1;
                expected = Some(
                    raw.get(i)
                        .unwrap_or_else(|| die("--expected needs an integer id"))
                        .parse()
                        .unwrap_or_else(|e| die(format!("--expected parse: {e}"))),
                );
            }
            "--top-k" => {
                i += 1;
                top_k = raw
                    .get(i)
                    .unwrap_or_else(|| die("--top-k needs an integer"))
                    .parse()
                    .unwrap_or_else(|e| die(format!("--top-k parse: {e}")));
            }
            "-h" | "--help" => {
                eprintln!(
                    "usage: gemma4-paris-probe --knot <path> --tokens <id,id,...> \
                     [--expected <id>] [--top-k <n>]"
                );
                std::process::exit(0);
            }
            other => die(format!("unknown arg: {other}")),
        }
        i += 1;
    }

    let knot = knot.unwrap_or_else(|| die("--knot required"));
    let tokens: Vec<u32> = tokens_str
        .unwrap_or_else(|| die("--tokens required"))
        .split(',')
        .map(|s| s.trim())
        .filter(|s| !s.is_empty())
        .map(|s| s.parse::<u32>().unwrap_or_else(|e| die(format!("--tokens parse {s:?}: {e}"))))
        .collect();
    if tokens.is_empty() {
        die("--tokens parsed to empty list");
    }

    Args {
        knot,
        tokens,
        expected,
        top_k,
    }
}

fn main() {
    let args = parse_args();
    let t0 = Instant::now();
    eprintln!(
        "gemma4-paris-probe: knot={} tokens={:?} expected={:?}",
        args.knot, args.tokens, args.expected
    );

    // 1. Load the dense .knot.
    let t = Instant::now();
    let knot = KnotWeights::load(&args.knot).unwrap_or_else(|e| die(format!("knot load: {e:?}")));
    let cfg = knot
        .config
        .as_ref()
        .unwrap_or_else(|| die("knot has no config block (gemma4 needs config)"));
    eprintln!(
        "  loaded knot in {:.2}s  arch={} hidden={} layers={} heads={} kv={} head_dim={} vocab={} \
         rope_theta={} sw_pat={:?} sw={:?} g_hd={:?} qpas={:?} softcap={:?} prf={:?}",
        t.elapsed().as_secs_f32(),
        cfg.arch,
        cfg.hidden_dim,
        cfg.num_layers,
        cfg.num_heads,
        cfg.num_kv_heads,
        cfg.head_dim,
        cfg.vocab_size,
        cfg.rope_theta,
        cfg.sliding_window_pattern,
        cfg.sliding_window,
        cfg.global_head_dim,
        cfg.query_pre_attn_scalar,
        cfg.final_logit_softcap,
        cfg.rope_partial_factor,
    );
    if !matches!(cfg.arch.as_str(), "gemma3" | "gemma4") {
        die(format!("arch is {} — this probe only drives gemma3/gemma4", cfg.arch));
    }

    // 2. Build the pipeline (consumes the knot).
    let t = Instant::now();
    let mut pipeline =
        Gemma4Pipeline::from_knot(knot).unwrap_or_else(|e| die(format!("from_knot: {e}")));
    let hidden_dim = pipeline.config.hidden_dim;
    let num_layers = pipeline.config.num_layers;
    let seq_len = args.tokens.len();
    eprintln!("  built Gemma4Pipeline in {:.2}s", t.elapsed().as_secs_f32());

    // 3. Manual embed: dequant each token's row from token_embd_weight and
    //    apply Gemma embed scaling (* sqrt(hidden_dim)). Mirrors the smoke
    //    binary's proven path exactly.
    let t = Instant::now();
    let embed_ref = &pipeline.locs.embed;
    let embed_qtype = embed_ref.qtype;
    let embed_bytes = pipeline
        .knot
        .backend
        .fetch_tensor(&embed_ref.name)
        .unwrap_or_else(|e| die(format!("fetch {}: {e:?}", embed_ref.name)));
    let embed_scale = (hidden_dim as f32).sqrt();
    let mut residual = vec![0.0f32; seq_len * hidden_dim];
    let mut row_buf = vec![0.0f32; hidden_dim];
    for (i, &tid) in args.tokens.iter().enumerate() {
        let tok = tid as usize;
        match embed_qtype {
            QType::F32 => {
                let emb = bytes_to_f32_slice(&embed_bytes);
                let start = tok * hidden_dim;
                row_buf.copy_from_slice(&emb[start..start + hidden_dim]);
            }
            QType::F16 => dequantize_f16_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
            QType::Q4K => dequantize_q4k_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
            QType::Q5_0 => dequantize_q5_0_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
            QType::Q5K => dequantize_q5k_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
            QType::Q6K => dequantize_q6k_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
            QType::Q8_0 => dequantize_q8_0_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
        }
        for j in 0..hidden_dim {
            row_buf[j] *= embed_scale;
        }
        residual[i * hidden_dim..(i + 1) * hidden_dim].copy_from_slice(&row_buf);
    }
    drop(embed_bytes);
    eprintln!(
        "  embed: {:.2}s  qtype={embed_qtype:?} out={} floats",
        t.elapsed().as_secs_f32(),
        residual.len()
    );

    // 4. Forward all layers via the chunked attn/gate/up/down API.
    let t = Instant::now();
    let mut last_layer_out: Vec<f32> = residual.clone();
    for layer in 0..num_layers {
        let is_first = layer == 0;
        let is_last = layer == num_layers - 1;
        let lt = Instant::now();
        let attn_input: &[f32] = if is_first { &residual[..] } else { &[] };
        pipeline
            .forward_range_attn_chunk(attn_input, layer, 0, seq_len, is_first)
            .unwrap_or_else(|e| die(format!("attn L{layer}: {e}")));
        pipeline
            .forward_range_ffn_gate_chunk(layer, seq_len)
            .unwrap_or_else(|e| die(format!("ffn_gate L{layer}: {e}")));
        pipeline
            .forward_range_ffn_up_chunk(layer, seq_len)
            .unwrap_or_else(|e| die(format!("ffn_up L{layer}: {e}")));
        let out = pipeline
            .forward_range_ffn_down_chunk(layer, seq_len, is_last)
            .unwrap_or_else(|e| die(format!("ffn_down L{layer}: {e}")));
        if is_last {
            last_layer_out = out;
        }
        let last_off = (seq_len - 1) * hidden_dim;
        let resid = pipeline.get_residual(seq_len);
        let last_tok = &resid[last_off..last_off + hidden_dim];
        let max = last_tok.iter().fold(0.0f32, |a, &b| a.max(b.abs()));
        let mean = last_tok.iter().map(|&v| v.abs()).sum::<f32>() / hidden_dim as f32;
        let sum_sq: f32 = last_tok.iter().map(|&v| v * v).sum();
        let rms = (sum_sq / hidden_dim as f32).sqrt();
        let nan = last_tok.iter().filter(|v| v.is_nan()).count();
        let kind = if pipeline.is_global_layer(layer) { "G" } else { "S" };
        eprintln!(
            "    L{:>2}/{} [{}] {:>4} ms  max={:.3} mean={:.3} rms={:.3} nan={}",
            layer,
            num_layers,
            kind,
            lt.elapsed().as_millis(),
            max,
            mean,
            rms,
            nan
        );
    }
    eprintln!("  {} layers: {:.2}s", num_layers, t.elapsed().as_secs_f32());

    // 5. lm_head_only: final RMSNorm + tied lm_head matmul + tanh logit softcap.
    let t = Instant::now();
    let logits = pipeline
        .lm_head_only(&last_layer_out, seq_len)
        .unwrap_or_else(|e| die(format!("lm_head_only: {e}")));
    eprintln!(
        "  lm_head_only: {:.2}s  vocab={}",
        t.elapsed().as_secs_f32(),
        logits.len()
    );
    if logits.is_empty() {
        die("lm_head_only returned empty slice");
    }

    let nan = logits.iter().filter(|x| x.is_nan()).count();
    let inf = logits.iter().filter(|x| x.is_infinite()).count();
    if nan > 0 || inf > 0 {
        eprintln!("  WARNING: {nan} NaN, {inf} Inf logits");
    }

    // 6. Top-K argmax.
    let mut order: Vec<usize> = (0..logits.len()).collect();
    order.sort_unstable_by(|&a, &b| {
        logits[b]
            .partial_cmp(&logits[a])
            .unwrap_or(std::cmp::Ordering::Equal)
    });

    println!("\n── gemma4-paris-probe top-{} ──", args.top_k);
    for r in 0..args.top_k.min(order.len()) {
        let id = order[r];
        println!("  rank {r}: token_id={id:>6}  logit={:+.6}", logits[id]);
    }

    let argmax_id = order.first().copied().unwrap_or(usize::MAX) as u32;
    eprintln!("\n  wall={:.2}s", t0.elapsed().as_secs_f32());

    match args.expected {
        Some(want) if argmax_id == want => {
            println!("\nPASS: argmax token_id={argmax_id} matches expected {want}");
            std::process::exit(0);
        }
        Some(want) => {
            let rank = order.iter().position(|&i| i as u32 == want);
            match rank {
                Some(r) => println!(
                    "\nFAIL: argmax token_id={argmax_id} != expected {want} (expected at rank {r}, logit={:+.6})",
                    logits[want as usize]
                ),
                None => println!("\nFAIL: argmax token_id={argmax_id} != expected {want}"),
            }
            std::process::exit(1);
        }
        None => {
            println!("\nargmax token_id={argmax_id} (no --expected supplied — informational)");
            std::process::exit(0);
        }
    }
}
